  return cleanText(value)
    .toLowerCase()
    .replace(/^[\/!#.]+/, "")
    .replace(/[\u2018\u2019]/g, "'")
    .replace(/[\u201c\u201d]/g, "\"")
    .replace(/[!?.,]+$/g, "")
